/// <summary>
/// Import bank balances
/// </summary>
public class ETG_Acu_BankBalanceImport extends ETG_Acu_DataImportBase
{
    LedgerJournalId         journalNum;

}

Method.Source:
public static void main(Args args)
{
    ETG_Acu_BankBalanceImport  bankBalanceImport;

    bankBalanceImport = ETG_Acu_BankBalanceImport::construct();

    if (bankBalanceImport.prompt())
    {
        bankBalanceImport.runOperation();
    }
}

/// <summary>
/// Constructs ETG_Acu_BankBalanceImport
/// </summary>
/// <returns>Object ETG_Acu_BankBalanceImport</returns>
public static ETG_Acu_BankBalanceImport construct()
{
    return new ETG_Acu_BankBalanceImport();
}

/// <summary>
/// Describes whether the class is designed for execution in a new session.
/// </summary>
/// <returns>
/// true if the class is designed for execution the operation in a new session; otherwise, false.
/// </returns>
protected boolean canRunInNewSession()
{
    return false;
}

/// <summary>
/// Performs the actual job of import
/// </summary>
/// <param name = "_con">Container of current record</param>
protected void processData(container _con)
{
    LedgerJournalEntity     ledgerJournal;
    NumberSeq               numberSeq;

    if (!journalNum)
    {
        numberSeq = NumberSeq::newGetNum(LedgerParameters::numRefJournalNum());

        journalNum = numberSeq.num();
    }

    ledgerJournal.JournalBatchNumber            = journalNum;
    ledgerJournal.LineNumber                    = conpeek(_con, 2);
    ledgerJournal.AccountDisplayValue           = conpeek(_con, 3);
    ledgerJournal.AccountType                   = LedgerJournalACType::Bank;
    ledgerJournal.CreditAmount                  = conpeek(_con, 5);
    ledgerJournal.CurrencyCode                  = conpeek(_con, 6);
    ledgerJournal.DebitAmount                   = conpeek(_con, 7);
    ledgerJournal.JournalName                   = conpeek(_con, 8);
    ledgerJournal.OffsetAccountDisplayValue     = conpeek(_con, 9) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                    + conPeek(_con, 18) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                    + conPeek(_con, 16) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                    + conPeek(_con, 20) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                    + conPeek(_con, 19) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                    + conPeek(_con, 14) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                    + conPeek(_con, 17) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                    + conPeek(_con, 15);

    ledgerJournal.OffsetAccountType             = conpeek(_con, 10);
    ledgerJournal.PostingLayer                  = conpeek(_con, 11);
    ledgerJournal.TransDate                     = str2Date(conpeek(_con, 12), 123); // DD/MM/YYYY

    // BusinessUnit (14)	Contract (15)	Department (16)	Intercompany (17)	Plant_Warehouse_Office (18)	Product_Service (19)	Trader_Employee (20)
    // 18-16-15-20-19-14-17

    ledgerJournal.DefaultDimensionDisplayValue  = conPeek(_con, 18) + enum2Str(dimensionParameters.DimensionSegmentDelimiter) 
                                                + conPeek(_con, 16) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 20) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 19) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 14) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 17) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 15);
    ledgerJournal.insert();
}

/// <summary>
/// Import Bank balance
/// </summary>
/// <returns>Caption</returns>
public ClassDescription caption()
{
    ClassDescription ret;

    ret = "@ETG_ENG_Labels:ImportBankBalance";

    return ret;
}
